head.b:skin:

/* ==============================================
   CLAUDE.AI THEME FOR BLOGGER — Fattan Dev
   v1.0.0
   ============================================== */

/* Variable definitions
   ====================
   <Variable name="keycolor" description="Main Color" type="color" default="#d97706" value="#d97706"/>
   <Variable name="startSide" description="Side where text starts" type="automatic" default="left"/>
   <Variable name="endSide" description="Side where text ends" type="automatic" default="right"/>

   <Group description="Page Text" selector="body">
     <Variable name="body.font" description="Font" type="font" default="normal normal 15px Inter, sans-serif" value="normal normal 15px Inter, sans-serif"/>
     <Variable name="body.text.color" description="Text Color" type="color" default="#e2e8f0" value="#e2e8f0"/>
   </Group>

   <Group description="Backgrounds" selector=".body-fauxcolumns-outer">
     <Variable name="body.background.color" description="Outer Background" type="color" default="#0f172a" value="#0f172a"/>
     <Variable name="content.background.color" description="Main Background" type="color" default="#0f172a" value="#0f172a"/>
     <Variable name="header.background.color" description="Header Background" type="color" default="transparent" value="transparent"/>
   </Group>

   <Group description="Links" selector=".main-outer">
     <Variable name="link.color" description="Link Color" type="color" default="#d97706" value="#d97706"/>
     <Variable name="link.visited.color" description="Visited Color" type="color" default="#92400e" value="#92400e"/>
     <Variable name="link.hover.color" description="Hover Color" type="color" default="#f59e0b" value="#f59e0b"/>
   </Group>

   <Group description="Blog Title" selector=".header h1">
     <Variable name="header.font" description="Font" type="font" default="normal 600 28px Inter, sans-serif" value="normal 600 28px Inter, sans-serif"/>
     <Variable name="header.text.color" description="Title Color" type="color" default="#f8fafc" value="#f8fafc"/>
   </Group>

   <Group description="Blog Description" selector=".header .description">
     <Variable name="description.text.color" description="Description Color" type="color" default="#94a3b8" value="#94a3b8"/>
   </Group>

   <Group description="Tabs Text" selector=".tabs-inner .widget li a">
     <Variable name="tabs.font" description="Font" type="font" default="normal normal 13px Inter, sans-serif" value="normal normal 13px Inter, sans-serif"/>
     <Variable name="tabs.text.color" description="Text Color" type="color" default="#94a3b8" value="#94a3b8"/>
     <Variable name="tabs.selected.text.color" description="Selected Color" type="color" default="#f8fafc" value="#f8fafc"/>
   </Group>

   <Group description="Tabs Background" selector=".tabs-outer .PageList">
     <Variable name="tabs.background.color" description="Background Color" type="color" default="transparent" value="transparent"/>
     <Variable name="tabs.selected.background.color" description="Selected Color" type="color" default="#1e293b" value="#1e293b"/>
   </Group>

   <Group description="Post Title" selector="h3.post-title, .comments h4">
     <Variable name="post.title.font" description="Font" type="font" default="normal 600 22px Inter, sans-serif" value="normal 600 22px Inter, sans-serif"/>
   </Group>

   <Group description="Date Header" selector=".date-header">
     <Variable name="date.header.color" description="Text Color" type="color" default="#64748b" value="#64748b"/>
     <Variable name="date.header.background.color" description="Background Color" type="color" default="transparent" value="transparent"/>
     <Variable name="date.header.font" description="Text Font" type="font" default="normal 500 11px Inter, sans-serif" value="normal 500 11px Inter, sans-serif"/>
     <Variable name="date.header.padding" description="Date Header Padding" type="string" default="0.4em" value="0.4em"/>
     <Variable name="date.header.letterspacing" description="Date Header Letter Spacing" type="string" default="0.08em" value="0.08em"/>
     <Variable name="date.header.margin" description="Date Header Margin" type="string" default="inherit" value="inherit"/>
   </Group>

   <Group description="Post Footer" selector=".post-footer">
     <Variable name="post.footer.text.color" description="Text Color" type="color" default="#64748b" value="#64748b"/>
     <Variable name="post.footer.background.color" description="Background Color" type="color" default="transparent" value="transparent"/>
     <Variable name="post.footer.border.color" description="Shadow Color" type="color" default="#1e293b" value="#1e293b"/>
   </Group>

   <Group description="Gadgets" selector="h2">
     <Variable name="widget.title.font" description="Title Font" type="font" default="normal 600 11px Inter, sans-serif" value="normal 600 11px Inter, sans-serif"/>
     <Variable name="widget.title.text.color" description="Title Color" type="color" default="#94a3b8" value="#94a3b8"/>
     <Variable name="widget.alternate.text.color" description="Alternate Color" type="color" default="#475569" value="#475569"/>
   </Group>

   <Group description="Images" selector=".main-inner">
     <Variable name="image.background.color" description="Background Color" type="color" default="#1e293b" value="#1e293b"/>
     <Variable name="image.border.color" description="Border Color" type="color" default="#334155" value="#334155"/>
     <Variable name="image.text.color" description="Caption Text Color" type="color" default="#94a3b8" value="#94a3b8"/>
   </Group>

   <Group description="Accents" selector=".content-inner">
     <Variable name="body.rule.color" description="Separator Line Color" type="color" default="#1e293b" value="#1e293b"/>
     <Variable name="tabs.border.color" description="Tabs Border Color" type="color" default="#1e293b" value="#1e293b"/>
   </Group>

   <Variable name="body.background" description="Body Background" type="background" color="$(body.background.color)" default="$(color) none repeat scroll top left" value="$(color) none repeat scroll top left"/>
   <Variable name="body.background.override" description="Body Background Override" type="string" default="" value=""/>
   <Variable name="body.background.gradient.cap" description="Body Gradient Cap" type="url" default="none" value="none"/>
   <Variable name="body.background.gradient.tile" description="Body Gradient Tile" type="url" default="none" value="none"/>
   <Variable name="content.background.color.selector" description="Content Background Color Selector" type="string" default=".content-inner" value=".content-inner"/>
   <Variable name="content.padding" description="Content Padding" type="length" default="10px" min="0" max="100px" value="0px"/>
   <Variable name="content.padding.horizontal" description="Content Horizontal Padding" type="length" default="10px" min="0" max="100px" value="0px"/>
   <Variable name="content.shadow.spread" description="Content Shadow Spread" type="length" default="0" min="0" max="100px" value="0"/>
   <Variable name="content.shadow.spread.webkit" description="Content Shadow Spread (WebKit)" type="length" default="0" min="0" max="100px" value="0"/>
   <Variable name="content.shadow.spread.ie" description="Content Shadow Spread (IE)" type="length" default="0" min="0" max="100px" value="0"/>
   <Variable name="main.border.width" description="Main Border Width" type="length" default="0" min="0" max="10px" value="0"/>
   <Variable name="header.background.gradient" description="Header Gradient" type="url" default="none" value="none"/>
   <Variable name="header.shadow.offset.left" description="Header Shadow Offset Left" type="length" default="0" min="-50px" max="50px" value="0"/>
   <Variable name="header.shadow.offset.top" description="Header Shadow Offset Top" type="length" default="0" min="-50px" max="50px" value="0"/>
   <Variable name="header.shadow.spread" description="Header Shadow Spread" type="length" default="0" min="0" max="100px" value="0"/>
   <Variable name="header.padding" description="Header Padding" type="length" default="0" min="0" max="100px" value="0"/>
   <Variable name="header.border.size" description="Header Border Size" type="length" default="0" min="0" max="10px" value="0"/>
   <Variable name="header.bottom.border.size" description="Header Bottom Border Size" type="length" default="0" min="0" max="10px" value="0"/>
   <Variable name="header.border.horizontalsize" description="Header Horizontal Border Size" type="length" default="0" min="0" max="10px" value="0"/>
   <Variable name="description.text.size" description="Description Text Size" type="string" default="14px" value="14px"/>
   <Variable name="tabs.margin.top" description="Tabs Margin Top" type="length" default="0" min="0" max="100px" value="0"/>
   <Variable name="tabs.margin.side" description="Tabs Side Margin" type="length" default="0" min="0" max="100px" value="0"/>
   <Variable name="tabs.background.gradient" description="Tabs Background Gradient" type="url" default="none" value="none"/>
   <Variable name="tabs.border.width" description="Tabs Border Width" type="length" default="1px" min="0" max="10px" value="1px"/>
   <Variable name="tabs.bevel.border.width" description="Tabs Bevel Border Width" type="length" default="0" min="0" max="10px" value="0"/>
   <Variable name="post.margin.bottom" description="Post Bottom Margin" type="length" default="0" min="0" max="100px" value="0"/>
   <Variable name="image.border.small.size" description="Image Border Small Size" type="length" default="0" min="0" max="10px" value="0"/>
   <Variable name="image.border.large.size" description="Image Border Large Size" type="length" default="0" min="0" max="10px" value="0"/>
   <Variable name="page.width.selector" description="Page Width Selector" type="string" default=".region-inner" value=".region-inner"/>
   <Variable name="page.width" description="Page Width" type="string" default="auto" value="auto"/>
   <Variable name="main.section.margin" description="Main Section Margin" type="length" default="0" min="0" max="100px" value="0"/>
   <Variable name="main.padding" description="Main Padding" type="length" default="0" min="0" max="100px" value="0"/>
   <Variable name="main.padding.top" description="Main Padding Top" type="length" default="0" min="0" max="100px" value="0"/>
   <Variable name="main.padding.bottom" description="Main Padding Bottom" type="length" default="0" min="0" max="100px" value="0"/>
   <Variable name="paging.background" color="$(content.background.color)" description="Background of blog paging area" type="background" default="transparent none no-repeat scroll top center" value="transparent none no-repeat scroll top center"/>
   <Variable name="footer.bevel" description="Bevel border length of footer" type="length" default="0" min="0" max="10px" value="0"/>
   <Variable name="mobile.background.overlay" description="Mobile Background Overlay" type="string" default="transparent none repeat scroll top left" value="transparent none repeat scroll top left"/>
   <Variable name="mobile.background.size" description="Mobile Background Size" type="string" default="auto" value="auto"/>
   <Variable name="mobile.button.color" description="Mobile Button Color" type="color" default="#d97706" value="#d97706"/>
*/

/* ============================================================
   ROOT TOKENS — claude.ai color palette
   ============================================================ */
:root {
  --font: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --font-mono: ui-monospace, 'Cascadia Code', 'Fira Code', monospace;

  /* Backgrounds */
  --bg-base:    #0f172a;
  --bg-surface: #1e293b;
  --bg-card:    #1e293b;
  --bg-hover:   #263044;
  --bg-input:   #0f172a;

  /* Text */
  --text-primary:   #e2e8f0;
  --text-secondary: #94a3b8;
  --text-muted:     #64748b;
  --text-hint:      #475569;

  /* Borders */
  --border:        #1e293b;
  --border-subtle: #334155;

  /* Accent — claude amber/orange */
  --accent:       #d97706;
  --accent-light: #fbbf24;
  --accent-dim:   rgba(217,119,6,.15);

  /* Status */
  --success: #10b981;
  --info:    #3b82f6;

  /* Sizing */
  --max-w:        1200px;
  --sidebar-w:    280px;
  --radius:       10px;
  --radius-sm:    6px;
  --radius-full:  999px;
  --trans:        150ms ease;
}

/* ============================================================
   RESET
   ============================================================ */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; }

body {
  font: $(body.font);
  font-family: var(--font);
  color: $(body.text.color);
  background: $(body.background) !important;
  background-color: var(--bg-base) !important;
  -webkit-font-smoothing: antialiased;
  line-height: 1.6;
  padding: 0 !important;
}

html body $(page.width.selector) {
  min-width: 0;
  max-width: 100%;
  width: $(page.width);
}

a:link   { color: $(link.color); text-decoration: none; transition: color var(--trans); }
a:visited{ color: $(link.visited.color); text-decoration: none; }
a:hover  { color: $(link.hover.color); text-decoration: none; }

img { max-width: 100%; height: auto; }

/* ============================================================
   STRIP DEFAULT BLOGGER CHROME
   ============================================================ */
.body-fauxcolumns,
.content-fauxcolumns,
.fauxcolumn-outer,
.fauxborder-left,
.fauxborder-right,
.fauxcolumn-inner,
.cap-top, .cap-bottom,
.cap-left, .cap-right,
.content-cap-top,
.content-cap-bottom,
.header-cap-top,
.header-cap-bottom,
.tabs-cap-top,
.tabs-cap-bottom,
.main-cap-top,
.main-cap-bottom,
.footer-cap-top,
.footer-cap-bottom { display: none !important; }

.content-outer {
  -moz-box-shadow: none !important;
  -webkit-box-shadow: none !important;
  box-shadow: none !important;
  margin: 0 !important;
}

.content-inner {
  padding: 0 !important;
  max-width: var(--max-w);
  margin: 0 auto;
}

$(content.background.color.selector) {
  background-color: $(content.background.color) !important;
}

/* ============================================================
   NAVBAR (Blogger top bar — hide it)
   ============================================================ */
.navbar { display: none !important; }

/* ============================================================
   HEADER
   ============================================================ */
.header-outer {
  background: var(--bg-base) !important;
  border-bottom: 1px solid var(--border-subtle);
  position: sticky;
  top: 0;
  z-index: 100;
}

.region-inner.header-inner {
  max-width: var(--max-w);
  margin: 0 auto;
  padding: 0 24px;
  display: flex;
  align-items: center;
  min-height: 58px;
}

.Header {
  display: flex;
  align-items: center;
  gap: 12px;
  flex: 1;
}

.Header h1, .header h1 {
  font: $(header.font);
  font-family: var(--font);
  font-weight: 600;
  font-size: 18px;
  letter-spacing: -0.02em;
  color: $(header.text.color);
}

.Header h1 a {
  color: $(header.text.color);
  display: flex;
  align-items: center;
  gap: 8px;
}

.Header h1 a::before {
  content: '';
  display: inline-block;
  width: 28px;
  height: 28px;
  background: var(--accent);
  border-radius: 7px;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 24 24' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M12 4C7.58 4 4 7.58 4 12s3.58 8 8 8 8-3.58 8-8-3.58-8-8-8z' fill='white' fill-opacity='.9'/%3E%3C/svg%3E");
  background-size: 18px;
  background-repeat: no-repeat;
  background-position: center;
  flex-shrink: 0;
}

.Header .description {
  display: none;
}

/* titlewrapper / descriptionwrapper */
.titlewrapper { padding: 0 !important; }
.descriptionwrapper { display: none; }

/* ============================================================
   TABS — topic nav strip
   ============================================================ */
.tabs-outer {
  background: var(--bg-base);
  border-bottom: 1px solid var(--border-subtle);
}

.region-inner.tabs-inner {
  max-width: var(--max-w);
  margin: 0 auto;
  padding: 0 24px;
}

.tabs-inner .section:first-child { border-top: none !important; }
.tabs-inner .section:first-child ul { border: none !important; margin: 0 !important; }

.tabs-inner .widget ul {
  background: none !important;
  border: none !important;
  border-bottom: none !important;
  margin: 0 !important;
  padding: 0;
  display: flex;
  gap: 0;
  overflow-x: auto;
  scrollbar-width: none;
  list-style: none;
}

.tabs-inner .widget ul::-webkit-scrollbar { display: none; }

.tabs-inner .widget li { list-style: none; }

.tabs-inner .widget li a {
  display: inline-flex;
  align-items: center;
  padding: 12px 16px;
  font-family: var(--font);
  font-size: 13px;
  font-weight: 500;
  color: $(tabs.text.color);
  border-left: none !important;
  border-right: none !important;
  border-bottom: 2px solid transparent;
  border-top: none;
  white-space: nowrap;
  transition: all var(--trans);
}

.tabs-inner .widget li a:hover,
.tabs-inner .widget li.selected a {
  color: $(tabs.selected.text.color);
  background: none !important;
  background-color: transparent !important;
  border-bottom-color: var(--accent);
  text-decoration: none;
}

/* ============================================================
   MAIN LAYOUT
   ============================================================ */
.main-outer {
  background: var(--bg-base) !important;
  border: none !important;
}

.region-inner.main-inner {
  max-width: var(--max-w);
  margin: 0 auto;
  padding: 0 !important;
}

.main-inner .columns {
  padding-left: 0 !important;
  padding-right: 0 !important;
  display: flex;
  gap: 0;
}

.column-center-outer {
  flex: 1;
  min-width: 0;
  padding: 32px 24px 60px;
}

.column-center-inner { padding: 0 !important; }
.main-inner .column-center-inner .section { margin: 0 !important; }

/* Right sidebar */
.column-right-outer {
  width: var(--sidebar-w);
  flex-shrink: 0;
}

.column-right-inner {
  padding: 32px 24px 60px 0;
  position: sticky;
  top: 120px;
  align-self: start;
}

.column-left-outer { display: none; }

/* ============================================================
   DATE HEADER
   ============================================================ */
h2.date-header {
  font: $(date.header.font);
  font-family: var(--font);
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  margin-bottom: 20px;
}

.date-header span {
  background: none !important;
  background-color: transparent !important;
  color: var(--text-muted) !important;
  padding: 0 !important;
  letter-spacing: 0.08em;
  margin: 0 !important;
}

/* ============================================================
   POST
   ============================================================ */
.post-outer {
  margin-bottom: 0 !important;
}

.date-outer {
  border-bottom: 1px solid var(--border-subtle);
  padding-bottom: 28px;
  margin-bottom: 28px;
}

.date-outer:last-child { border-bottom: none; }

.post {
  background: var(--bg-base) !important;
  margin: 0 !important;
}

/* Post title */
h3.post-title, .post-title {
  font-family: var(--font);
  font-size: 20px;
  font-weight: 600;
  letter-spacing: -0.02em;
  line-height: 1.35;
  margin: 0 0 10px !important;
}

h3.post-title a {
  color: var(--text-primary);
  transition: color var(--trans);
}

h3.post-title a:hover { color: var(--accent-light); }

/* Post header meta */
.post-header {
  display: none;
}

/* Post body */
.post-body {
  font-size: 15px;
  line-height: 1.7;
  color: var(--text-secondary);
  position: relative;
}

.post-body p { margin-bottom: 1.25em; }

.post-body h2 {
  font-size: 18px; font-weight: 600; color: var(--text-primary);
  margin: 1.75em 0 0.6em; letter-spacing: -0.01em;
}

.post-body h3 {
  font-size: 16px; font-weight: 600; color: var(--text-primary);
  margin: 1.5em 0 0.5em;
}

.post-body a:link { color: var(--accent); }
.post-body a:hover { color: var(--accent-light); }

.post-body strong { color: var(--text-primary); font-weight: 600; }

.post-body blockquote {
  border-left: 3px solid var(--accent);
  padding: 12px 20px;
  margin: 1.5em 0;
  background: var(--accent-dim);
  border-radius: 0 var(--radius-sm) var(--radius-sm) 0;
  color: var(--text-secondary);
  font-style: italic;
}

.post-body pre {
  background: var(--bg-surface);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-sm);
  padding: 16px 20px;
  font-family: var(--font-mono);
  font-size: 13px;
  line-height: 1.6;
  overflow-x: auto;
  color: var(--text-primary);
  margin: 1.25em 0;
}

.post-body code {
  font-family: var(--font-mono);
  font-size: 0.875em;
  background: var(--bg-surface);
  border: 1px solid var(--border-subtle);
  border-radius: 4px;
  padding: 2px 6px;
  color: var(--accent-light);
}

.post-body pre code {
  background: none; border: none; padding: 0;
  color: inherit; font-size: 1em;
}

.post-body img, .post-body .tr-caption-container {
  padding: 0 !important;
  background: var(--bg-surface) !important;
  border: 1px solid var(--border-subtle) !important;
  border-radius: var(--radius-sm) !important;
  box-shadow: none !important;
  -moz-box-shadow: none !important;
  -webkit-box-shadow: none !important;
  margin: 1em 0;
}

.post-body img {
  border-radius: var(--radius-sm);
  max-width: 100%;
  height: auto;
}

/* Jump link */
.jump-link a {
  display: inline-flex;
  align-items: center;
  gap: 6px;
  padding: 8px 18px;
  background: var(--accent-dim);
  color: var(--accent);
  border: 1px solid var(--accent);
  border-radius: var(--radius-full);
  font-size: 13px;
  font-weight: 500;
  margin-top: 16px;
  transition: all var(--trans);
}

.jump-link a:hover {
  background: var(--accent);
  color: #0f172a;
}

/* ============================================================
   POST FOOTER
   ============================================================ */
.post-footer {
  margin: 20px 0 0 !important;
  padding: 12px 0 0 !important;
  border-bottom: none !important;
  border-top: 1px solid var(--border-subtle) !important;
  background: transparent !important;
  background-color: transparent !important;
  font-size: 12px;
  color: var(--text-muted);
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  gap: 12px;
  line-height: 1.5;
}

.post-footer-line { display: inline-flex; align-items: center; gap: 8px; flex-wrap: wrap; }
.post-footer-line-1 { flex: 1; }

/* Hide share icons, email icons */
.post-share-buttons,
.goog-inline-block.share-button,
.post-icons,
.item-action,
.post-footer .item-control { display: none !important; }

/* Labels */
.post-labels {
  display: inline-flex;
  flex-wrap: wrap;
  gap: 6px;
}

.post-labels a {
  display: inline-flex;
  align-items: center;
  padding: 3px 10px;
  background: var(--accent-dim);
  color: var(--accent);
  border-radius: var(--radius-full);
  font-size: 11px;
  font-weight: 500;
  transition: all var(--trans);
}

.post-labels a:hover {
  background: var(--accent);
  color: #0f172a;
}

/* Timestamp */
.post-timestamp a {
  color: var(--text-muted);
  font-size: 12px;
}

/* Author */
.post-author { color: var(--text-muted); font-size: 12px; }
.post-author a { color: var(--text-secondary); }

/* Comment link */
.comment-link {
  color: var(--text-muted);
  font-size: 12px;
  transition: color var(--trans);
}
.comment-link:hover { color: var(--accent); }

/* Author profile card at post bottom */
.author-profile {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  padding: 16px;
  background: var(--bg-surface);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius);
  margin-top: 24px;
}

.author-profile img {
  border-radius: 50% !important;
  width: 40px !important;
  height: 40px !important;
  object-fit: cover;
}

/* ============================================================
   BLOG PAGER
   ============================================================ */
.blog-pager {
  background: transparent !important;
  display: flex;
  justify-content: center;
  align-items: center;
  gap: 12px;
  padding: 32px 0;
  margin-top: 16px;
  border-top: 1px solid var(--border-subtle);
}

.blog-pager-older-link,
.blog-pager-newer-link,
.home-link {
  background: var(--bg-surface) !important;
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-full);
  padding: 8px 20px !important;
  font-family: var(--font);
  font-size: 13px;
  font-weight: 500;
  color: var(--text-secondary) !important;
  transition: all var(--trans);
}

.blog-pager-older-link:hover,
.blog-pager-newer-link:hover,
.home-link:hover {
  border-color: var(--accent);
  color: var(--accent) !important;
}

/* ============================================================
   COMMENTS
   ============================================================ */
#comments {
  margin: 40px 0 0;
  font-family: var(--font);
}

#comments h4 {
  font-size: 14px;
  font-weight: 600;
  color: var(--text-primary);
  margin-bottom: 20px;
  letter-spacing: 0.04em;
  text-transform: uppercase;
}

#comments .comment-author {
  padding-top: 16px;
  border-top: 1px solid var(--border-subtle) !important;
  background: none !important;
  font-size: 13px;
  font-weight: 600;
  color: var(--text-primary);
}

#comments .comment-author:first-child {
  padding-top: 0;
  border-top: none !important;
}

#comments .comment-body p {
  font-size: 14px;
  color: var(--text-secondary);
  line-height: 1.65;
  margin: 6px 0 0;
}

#comments .comment-footer {
  margin-top: 6px;
}

#comments .comment-timestamp a {
  font-size: 11px;
  color: var(--text-muted);
}

/* ============================================================
   WIDGETS — SIDEBAR
   ============================================================ */
div.widget > h2,
div.widget h2.title,
.widget h2 {
  font-family: var(--font) !important;
  font-size: 11px !important;
  font-weight: 600 !important;
  color: var(--text-muted) !important;
  letter-spacing: 0.08em !important;
  text-transform: uppercase !important;
  margin: 0 0 14px !important;
  padding: 0 !important;
}

.widget {
  margin-bottom: 32px !important;
  padding: 0 !important;
}

.widget-content { font-size: 13px; }

/* ============================================================
   SIDEBAR SECTIONS
   ============================================================ */
.sidebar { font-family: var(--font); }

/* Blog Search */
.BlogSearch .widget-content { }
.gsc-search-box table, .gsc-search-box tbody, .gsc-search-box tr { display: flex !important; width: 100% !important; }
.gsc-input { flex: 1 !important; }
.gsc-input input {
  width: 100% !important;
  background: var(--bg-input) !important;
  border: 1px solid var(--border-subtle) !important;
  border-radius: var(--radius-sm) var(--radius-sm) 0 0 !important;
  color: var(--text-primary) !important;
  font-family: var(--font) !important;
  font-size: 13px !important;
  padding: 8px 12px !important;
  outline: none !important;
  border-radius: var(--radius-sm) !important;
}
.gsc-search-button input {
  background: var(--accent) !important;
  border: none !important;
  border-radius: var(--radius-sm) !important;
  color: #0f172a !important;
  font-weight: 600 !important;
  font-size: 12px !important;
  padding: 8px 14px !important;
  cursor: pointer !important;
  font-family: var(--font) !important;
  margin-left: 6px !important;
  transition: background var(--trans) !important;
}
.gsc-search-button input:hover { background: var(--accent-light) !important; }

/* PageList */
.PageList ul { list-style: none !important; padding: 0 !important; }
.PageList li { margin-bottom: 4px !important; }
.PageList li a {
  display: flex !important;
  align-items: center !important;
  padding: 7px 10px !important;
  border-radius: var(--radius-sm) !important;
  font-size: 13px !important;
  color: var(--text-secondary) !important;
  transition: all var(--trans) !important;
}
.PageList li a:hover,
.PageList li.selected a {
  background: var(--bg-hover) !important;
  color: var(--text-primary) !important;
}

/* Profile */
.profile-datablock { font-size: 13px; }
.profile-name-link { color: var(--text-primary) !important; font-weight: 500; }
.profile-name-link:hover { color: var(--accent) !important; }
.profile-textblock { color: var(--text-muted); font-size: 13px; line-height: 1.6; margin-top: 6px; }
.profile-link { font-size: 12px; color: var(--accent) !important; margin-top: 8px; display: inline-block; }
.profile-img {
  border-radius: 50% !important;
  border: 2px solid var(--border-subtle) !important;
  margin-bottom: 10px;
  box-shadow: none !important;
  -moz-box-shadow: none !important;
  -webkit-box-shadow: none !important;
}

/* Archive */
#ArchiveList select, .BlogArchive select {
  width: 100%;
  background: var(--bg-input);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius-sm);
  color: var(--text-secondary);
  font-family: var(--font);
  font-size: 13px;
  padding: 8px 12px;
  outline: none;
  cursor: pointer;
  appearance: none;
  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 16 16' fill='none' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M4 6l4 4 4-4' stroke='%2364748b' stroke-width='1.5' stroke-linecap='round' stroke-linejoin='round'/%3E%3C/svg%3E");
  background-repeat: no-repeat;
  background-position: right 10px center;
  background-size: 16px;
}

#ArchiveList select:focus { border-color: var(--accent); }

/* Label widget */
.Label .widget-content,
.list-label-widget-content ul {
  list-style: none !important;
  padding: 0 !important;
  display: flex;
  flex-wrap: wrap;
  gap: 6px;
}

.list-label-widget-content ul { flex-direction: column; gap: 0; }

.list-label-widget-content li {
  margin: 0 !important;
  border-bottom: 1px solid var(--border-subtle);
}

.list-label-widget-content li:last-child { border-bottom: none; }

.list-label-widget-content li a {
  display: flex;
  align-items: center;
  padding: 7px 0;
  font-size: 13px;
  color: var(--text-secondary) !important;
  transition: color var(--trans);
  justify-content: space-between;
}

.list-label-widget-content li a:hover { color: var(--accent) !important; }

/* Popular Posts */
.PopularPosts .widget-content ul {
  list-style: none !important;
  padding: 0 !important;
}

.PopularPosts li {
  padding: 12px 0 !important;
  border-bottom: 1px solid var(--border-subtle);
}

.PopularPosts li:last-child { border-bottom: none; }

.item-thumbnail { display: none !important; }

.item-title a {
  font-size: 14px !important;
  font-weight: 500 !important;
  color: var(--text-secondary) !important;
  line-height: 1.35 !important;
  display: block !important;
}

.item-title a:hover { color: var(--accent) !important; }

.item-snippet {
  font-size: 12px !important;
  color: var(--text-muted) !important;
  margin-top: 4px !important;
  line-height: 1.4 !important;
  display: -webkit-box !important;
  -webkit-line-clamp: 2 !important;
  -webkit-box-orient: vertical !important;
  overflow: hidden !important;
}

/* Stats */
.Stats .widget-content {
  font-size: 24px;
  font-weight: 700;
  color: var(--text-primary);
  letter-spacing: -0.02em;
}

/* Translate */
#google_translate_element { font-size: 12px; }

/* BlogList */
.BlogList .widget-content ul { list-style: none !important; padding: 0 !important; }
.BlogList li { padding: 10px 0 !important; border-bottom: 1px solid var(--border-subtle); }
.BlogList li:last-child { border-bottom: none; }
.blog-title a { font-size: 13px; font-weight: 500; color: var(--text-secondary) !important; }
.blog-title a:hover { color: var(--accent) !important; }
.item-title { font-size: 12px; color: var(--text-muted); }
.blog-icon { display: none; }

/* ReportAbuse */
.ReportAbuse { display: none !important; }

/* FeaturedPost */
.FeaturedPost { display: none !important; }

/* AdSense */
.AdSense .widget-content {
  background: var(--bg-surface);
  border: 1px solid var(--border-subtle);
  border-radius: var(--radius);
  padding: 12px;
  text-align: center;
  font-size: 11px;
  color: var(--text-muted);
}

/* Wikipedia */
.Wikipedia { display: none !important; }

/* Feed links */
.feed-links, .blog-feeds, .post-feeds { display: none !important; }

/* ============================================================
   FOOTER
   ============================================================ */
.footer-outer {
  background: var(--bg-base) !important;
  border-top: 1px solid var(--border-subtle) !important;
  margin-top: 60px;
}

.region-inner.footer-inner {
  max-width: var(--max-w);
  margin: 0 auto;
  padding: 40px 24px;
  display: flex;
  flex-wrap: wrap;
  gap: 40px;
}

.foot { flex: 1; min-width: 200px; }

.foot .widget > h2 { margin-bottom: 14px !important; }

/* Footer LinkList */
.foot .LinkList ul { list-style: none !important; padding: 0 !important; }
.foot .LinkList li { margin-bottom: 8px !important; }
.foot .LinkList a { font-size: 13px; color: var(--text-muted) !important; }
.foot .LinkList a:hover { color: var(--accent) !important; }

/* Footer Text widget */
.foot .Text .widget-content {
  font-size: 13px;
  color: var(--text-muted);
  line-height: 1.6;
}

/* Attribution */
.Attribution {
  width: 100%;
  text-align: center;
  padding: 16px 0 0;
  font-size: 12px;
  color: var(--text-muted);
  border-top: 1px solid var(--border-subtle);
}

/* Footer section columns hack */
.section-columns { width: 100% !important; border: none !important; }
.section-columns td { border: none !important; padding: 0 16px 0 0 !important; vertical-align: top !important; }
.section-columns td.first { padding-left: 0 !important; }

/* ============================================================
   SCROLLBAR
   ============================================================ */
::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: transparent; }
::-webkit-scrollbar-thumb { background: var(--border-subtle); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: var(--text-hint); }

/* ============================================================
   SELECTION
   ============================================================ */
::selection { background: var(--accent-dim); color: var(--accent-light); }

/* ============================================================
   FOCUS
   ============================================================ */
:focus-visible { outline: 2px solid var(--accent); outline-offset: 2px; border-radius: 3px; }

/* ============================================================
   RESPONSIVE
   ============================================================ */
@media (max-width: 900px) {
  .column-right-outer { display: none; }
  .main-inner .columns { flex-direction: column; }
  .column-center-outer { padding: 24px 16px 40px; }
  .region-inner.header-inner { padding: 0 16px; }
  .region-inner.tabs-inner { padding: 0 16px; }
  .region-inner.footer-inner { padding: 24px 16px; gap: 24px; }
}

@media (max-width: 600px) {
  h3.post-title { font-size: 17px !important; }
  .post-body { font-size: 14px; }
}

/* ============================================================
   BLOGGER LAYOUT EDITOR
   ============================================================ */
body#layout .region-inner { min-width: 0 !important; }
body#layout .columns { display: block !important; }
body#layout .column-right-outer { width: 30% !important; float: right !important; }
body#layout .column-center-outer { float: left !important; width: 70% !important; }
body#layout .header-outer { position: static !important; }
body#layout .tabs-outer { position: static !important; }

